  function _transferAsset(
    address to,
    address asset,
    uint256 amount
  ) internal {
    if (to == address(0) || asset == address(0)) {
      revert Errors.InvalidZeroAddress();
    }
    if (amount == 0) {
      revert Errors.InvalidZeroAmount();
    }

    IERC20(asset).safeTransfer(to, amount);
  }
}

