   590→  /// @dev precondition - Removed assets must not have a live auction.
   591→  /// @dev precondition - Removed assets must be have already set params.
   592→  /// @dev precondition - Added/updated asset must be allowlisted.
   593→  /// @dev precondition - Added/updated staleness threshold must be greater than zero.
   594→  /// @dev precondition - Added/updated auction duration must be greater than zero.
   595→  /// @dev precondition - Added/updated minimum auction size in USD must be greater than zero.
   596→  /// @dev precondition - Added/updated decay rate must be valid based on auction duration and max discount.
   597→  /// @dev precondition - Added/updated asset decimals must match the actual asset decimals.
   598→  function _applyAssetParamsUpdates(
   599→    ApplyAssetParamsUpdate[] calldata adds,
   600→    address[] calldata removes
   601→  ) private {
   602→    if (adds.length == 0 && removes.length == 0) {
   603→      revert Errors.EmptyList();
   604→    }
   605→
   606→    address assetOut = s_assetOut;
   607→
   608→    for (uint256 i; i < removes.length; ++i) {
   609→      address asset = removes[i];
   610→
   611→      if ((asset == assetOut && _liveAuctionExists()) || s_auctionStarts[asset] != 0) {
   612→        revert LiveAuction();
